impl Solution { pub fn rob(black_n: Vec<i32>, black_c: Vec<i32>) -> i64 { let black_len = black_n.len(); let mut black_dp = vec![0i64; black_len + 1]; for i in 0..black_len { black_dp[i+1] = black_dp[i]; if i >= 1 && black_c[i] != black_c[i-1] { black_dp[i+1] = black_dp[i+1].max(black_dp[i] + black_n[i] as i64); } if i >= 1 { black_dp[i+1] = black_dp[i+1].max(black_dp[i-1] + black_n[i] as i64); } else { black_dp[i+1] = black_dp[i+1].max(black_n[i] as i64); } } black_dp[black_len] } }